signer.rust_types:
use std::collections::{BTreeMap, HashMap};

pub struct Clearinghouse { data: [u8; 0x300] }
pub struct AdlFillCtx { data: [u8; 0x60] }

use std::collections::BTreeMap;
pub struct UnitQty { pub unit: u64, pub hi: i64, pub lo: u64 }
pub struct MarginAndShortfall {
    pub equity: Option<UnitQty>,
    pub margin_req: Option<UnitQty>,
    pub abs_notional: Option<UnitQty>,
    pub raw_equity: Option<UnitQty>,
}
pub struct AssetPosition {
    pub coin: u64,
    pub szi: i64,
    pub entry_px: u64,
    pub leverage: u64,
    pub liq_px: u64,
    pub margin: u64,
    pub funding: i64,
    pub flags: u64,
}
pub struct UserState {
    pub equity: UnitQty,
    pub raw_equity: UnitQty,
    pub positions: BTreeMap<u64, AssetPosition>,
}
pub struct OracleData {
    pub _0: u64,
    pub mark_px: u64,
    pub oracle_px: u64,
}

use std::collections::HashMap;

pub struct AssetInfo {
    market_state: u128,
    extra: u64,
}

pub struct OracleAsset {
    by_name: HashMap<String, u64>,
    history: Vec<u64>,
    open_interest: u64,
    cumulative: u64,
    user_id: u64,
    leverage_extras: Vec<u64>,
    assets: &'static [AssetEntry],
}

pub struct AssetEntry {
    body: [u64; 26],
}

pub struct PositionItem {
    body: [u64; 25],
}

pub struct Clearinghouse {
    head: u64,
    positions: &'static [PositionItem],
}

pub enum LiquidationCheck {
    Margin { unit: u64, value: u64 },
    None,
    Capped { value: u64 },
}
